-- FSI_DEMO_DB.CAPITAL_MARKETS.SECURITIES

CREATE OR REPLACE TABLE FSI_DEMO_DB.CAPITAL_MARKETS.SECURITIES (

    SECURITY_ID VARCHAR(20) NOT NULL,
    TICKER VARCHAR(10),
    CUSIP VARCHAR(9),
    ISIN VARCHAR(12),
    SECURITY_NAME VARCHAR(200),
    SECURITY_TYPE VARCHAR(30),
    ASSET_CLASS VARCHAR(30),
    EXCHANGE VARCHAR(20),
    SECTOR VARCHAR(50),
    INDUSTRY VARCHAR(100),
    COUNTRY VARCHAR(50),
    CURRENCY VARCHAR(3),
    ISSUE_DATE DATE,
    MATURITY_DATE DATE,
    COUPON_RATE NUMBER(5,4),
    PAR_VALUE NUMBER(15,2),
    IS_ACTIVE BOOLEAN DEFAULT TRUE,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (SECURITY_ID)

);

